#include<bits/stdc++.h>
using namespace std;
long long dp[11][101][1025],cnt[1025],v[1025];
int main()
{
    long long n,K,tot=0;
    scanf("%lld%lld",&n,&K);
    for(long long i=0;i<(1<<n);i++)
    {
        cnt[i]=__builtin_popcount(i);
        if(!(i&((i<<1)|(i>>1))))
        {
            v[++tot]=i;
        }
    }
    dp[0][0][0]=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=tot;j++)
        {
            long long v=::v[j];
            for(long long k=1;k<=tot;k++)
            {
                long long u=::v[k];
                if(!(v&((u<<1)|(u>>1)|u)))
                {
                    for(long long l=cnt[v];l<=K;l++)
                    {
                        dp[i][l][v]+=dp[i-1][l-cnt[v]][u];
                    }
                }
            }
        }
    }
    long long ans=0;
    for(long long i=1;i<=tot;i++)
    {
        ans+=dp[n][K][v[i]];
    }
    printf("%lld",ans);
    return 0;
}
